INSERT INTO public.wiki_pages (id, room_id, title, content, parent_id, created_at, updated_at) VALUES ('6a78599b-82ab-4de3-914d-76da15f88e74', 'c3497459-c4bf-4a9e-a01e-032f1a3f4df0', 'Animæ', '<p><strong><u>Génesis</u></strong></p><p><br></p><p>En el principio de la creación, los Dioses Primigenios exhalaron el Animæ, una esencia divina que infundió vida y forma a todo lo que existe. Este suspiro cósmico se entrelazó con las estrellas, los vientos y los árboles, dando origen a la vasta y diversa creación. Los elfos, seres sensibles y longevos, fueron los primeros en escuchar y entender los susurros del Animæ, percibiendo la interconexión de todo en el universo.</p><p><br></p><p>A través del Animæ, los elfos reconocen que la creación está compuesta de tres principios fundamentales: Caos, Neutralidad y Legalidad. Estos principios, aunque aparentemente opuestos, se entretejen en una danza armoniosa que mantiene el equilibrio del cosmos. Los elfos buscan entender y armonizar estos principios, creyendo que solo a través de esta comprensión pueden alcanzar la trascendencia y unirse con los Dioses Primigenios en el paraíso divino.</p><p><br></p><p><img src="data:image/jpeg;base64,"></p><p><br></p><p><strong><u>Relaciones entre los fieles y la religión</u></strong></p><p><br></p><p>Los elfos comprenden que cada aspecto del Animæ tiene su lugar en el gran tapiz de la existencia. Se esfuerzan por encontrar armonía entre el Caos, la Neutralidad y la Legalidad, reconociendo que la verdadera iluminación proviene de abrazar los diversos y maravillosos aspectos de Animæ en todas sus múltiples formas; por lo que rara vez los credos interfieren entre ellos. A través de su devoción a las enseñanzas sagradas y su reverencia por la esencia divina que fluye a través de todas las cosas, los elfos recorren el camino del equilibrio y la sabiduría, asegurando que la luz de Animæ brille intensamente a lo largo de los siglos.</p><p><br></p><p>Se cree que solo aquellos elfos que son capaces de aceptar objetivamente a esta trinidad compuesta por Caos, Neutralidad y Legalidad, independientemente de su alineamiento, pueden abandonar sus longevas vidas y la rueda de la reencarnación para unirse al Animæ y trascender al divino paraíso de la Creación junto a los Dioses Primigenios.</p>', '0c12d0a6-9f25-4d34-a65f-3c37d904974e', '2025-08-31 15:34:14.509314', '2025-08-31 15:35:44.547');

